mapper.sql:
j.deleted_at IS NULL

  AND j.created_by = #{ownerOnlyUserId}


  AND (
    j.created_by = #{hrScope.hrUserId}

      OR j.sub_department_id IN
      #{sid}

  )


  AND j.status::text IN
  #{s}


  AND (
    j.title ILIKE '%' || #{q.keyword} || '%'
    OR j.description ILIKE '%' || #{q.keyword} || '%'
    OR to_tsvector('english', coalesce(j.description, ''))
       @@ plainto_tsquery('english', #{q.keyword})
    OR to_tsvector('simple', coalesce(j.description, ''))
       @@ plainto_tsquery('simple', #{q.keyword})
  )


  AND j.status::text IN
  #{s}


  AND j.work_type::text IN
  #{w}


  AND j.level::text IN
  #{l}


  AND j.sub_department_id = #{q.subDepartmentId}


  AND sd.parent_department_id = #{q.departmentId}


  AND sd.location ILIKE '%' || #{q.location} || '%'



  AND (j.salary_max IS NULL OR j.salary_max >= #{q.salaryMin})


  AND (j.salary_min IS NULL OR j.salary_min <= #{q.salaryMax})


  AND EXISTS (
    SELECT 1 FROM job_tags jt
    JOIN tags t ON t.id = jt.tag_id
    WHERE jt.job_id = j.id
      AND t.slug IN
      #{s}
  )

mapper.select:
SELECT j.id FROM jobs j
JOIN sub_departments sd ON sd.id = j.sub_department_id
WHERE j.deleted_at IS NULL

    AND (
      j.created_by = #{hrScope.hrUserId}

        OR j.sub_department_id IN
        #{sid}

    )

ORDER BY j.published_at DESC NULLS LAST, j.id DESC
LIMIT #{limit}
